import{_ as o,o as i,c as d,ae as r}from"./chunks/framework.Czhw_PXq.js";const h=JSON.parse('{"title":"中国区 Provider 扩展第二轮设计","description":"","frontmatter":{},"headers":[],"relativePath":"superpowers/specs/2026-03-26-china-provider-expansion-round2-design.zh-CN.md","filePath":"superpowers/specs/2026-03-26-china-provider-expansion-round2-design.zh-CN.md"}'),a={name:"superpowers/specs/2026-03-26-china-provider-expansion-round2-design.zh-CN.md"};function l(c,e,t,p,n,s){return i(),d("div",null,[...e[0]||(e[0]=[r('<h1 id="中国区-provider-扩展第二轮设计" tabindex="-1">中国区 Provider 扩展第二轮设计 <a class="header-anchor" href="#中国区-provider-扩展第二轮设计" aria-label="Permalink to &quot;中国区 Provider 扩展第二轮设计&quot;">​</a></h1><p><strong>日期：</strong> 2026-03-26</p><h2 id="范围" tabindex="-1">范围 <a class="header-anchor" href="#范围" aria-label="Permalink to &quot;范围&quot;">​</a></h2><p>本设计覆盖 Notemd 在首轮中国区 provider 扩展之后的下一轮扩展：</p><ol><li>新增 <code>Qwen Code</code> 作为面向编码场景的独立预设，而不是要求用户复用通用 <code>Qwen</code> 预设。</li><li>新增 <code>Z AI</code> 作为国际版 GLM/Zhipu 入口，与现有面向中国大陆 endpoint 的 <code>GLM</code> 预设并存。</li><li>新增 <code>Huawei Cloud MaaS</code> 作为一等公民预设，服务于通过华为云 OpenAI-compatible endpoint 接入托管模型的用户。</li><li>同步更新测试、文档和发布材料，使这些 provider 以与现有预设相同的质量门槛交付。</li></ol><p>这一轮明确排除需要新认证机制、provider 专属 SDK 逻辑或新 transport 类型的 provider。目标是在不增加协议复杂度的前提下，扩展中国区与 China-adjacent provider 覆盖。</p><h2 id="架构" tabindex="-1">架构 <a class="header-anchor" href="#架构" aria-label="Permalink to &quot;架构&quot;">​</a></h2><p>provider 系统应继续使用 <code>src/llmProviders.ts</code> 作为 preset 元数据的单一事实源。三个新 provider 都应表现为 registry entry，并复用 <code>src/llmUtils.ts</code> 中现有的 <code>openai-compatible</code> transport 路径。</p><p>不应引入新的 transport。runtime 调用应继续走共享的 OpenAI-compatible request builder 以及集中式 retry/fallback 逻辑。connection test 也应继续依赖 provider 元数据，决定该 preset 是先探测 <code>/models</code>，还是直接探测 <code>chat/completions</code>。</p><p>这意味着实现保持增量式：</p><ul><li>在 <code>src/llmProviders.ts</code> 中新增 registry entry</li><li>在测试文件中新增 provider 断言</li><li>更新 <code>README.md</code>、<code>README_zh.md</code> 与 <code>change.md</code></li><li>使用现有双语 release workflow 发布一个 patch 版本</li></ul><h2 id="provider-决策" tabindex="-1">Provider 决策 <a class="header-anchor" href="#provider-决策" aria-label="Permalink to &quot;Provider 决策&quot;">​</a></h2><h3 id="_1-qwen-code" tabindex="-1">1. Qwen Code <a class="header-anchor" href="#_1-qwen-code" aria-label="Permalink to &quot;1. Qwen Code&quot;">​</a></h3><p><code>Qwen Code</code> 应作为独立 preset 添加，而不是隐藏在 <code>Qwen</code> 的建议 model 中。</p><p>原因：</p><ul><li>最新 Cline 会将其单独暴露，而不是混在通用 Qwen 下</li><li>寻找 coding-specialized model 的用户，预期看到直接可选的 preset</li><li>它符合现有 OpenAI-compatible transport 与 chat-first API testing 模型</li></ul><p>预期形态：</p><ul><li>transport：<code>openai-compatible</code></li><li>category：<code>cloud</code></li><li>API key mode：<code>required</code></li><li>API test mode：<code>chat-only</code></li><li>base URL：DashScope compatible-mode endpoint</li><li>默认 model：例如 <code>qwen3-coder-plus</code> 这类 Qwen coding model</li></ul><h3 id="_2-z-ai" tabindex="-1">2. Z AI <a class="header-anchor" href="#_2-z-ai" aria-label="Permalink to &quot;2. Z AI&quot;">​</a></h3><p>虽然 Notemd 已经包含 <code>GLM</code>，<code>Z AI</code> 仍应作为独立 preset 新增。</p><p>原因：</p><ul><li>最新 Cline 把 <code>Z AI</code> 视为一等 provider，而不是重复命名</li><li>当前 <code>GLM</code> preset 面向中国大陆的 <code>open.bigmodel.cn</code></li><li>单独的 <code>Z AI</code> preset 可以给用户提供国际 endpoint，同时不破坏现有 <code>GLM</code> 行为</li></ul><p>预期形态：</p><ul><li>transport：<code>openai-compatible</code></li><li>category：<code>cloud</code></li><li>API key mode：<code>required</code></li><li>API test mode：<code>chat-only</code></li><li>base URL：国际版 <code>https://api.z.ai/api/paas/v4</code></li><li>默认 model：<code>glm-5</code></li></ul><h3 id="_3-huawei-cloud-maas" tabindex="-1">3. Huawei Cloud MaaS <a class="header-anchor" href="#_3-huawei-cloud-maas" aria-label="Permalink to &quot;3. Huawei Cloud MaaS&quot;">​</a></h3><p><code>Huawei Cloud MaaS</code> 应作为一等公民 preset，为在华为云上托管 DeepSeek/Qwen 等模型的用户提供支持。</p><p>原因：</p><ul><li>最新 Cline 已直接内置</li><li>它是有意义的新增入口，而不是对现有 preset 的重命名</li><li>它的文档 endpoint 可以直接纳入现有 OpenAI-compatible runtime</li></ul><p>预期形态：</p><ul><li>transport：<code>openai-compatible</code></li><li>category：<code>cloud</code></li><li>API key mode：<code>required</code></li><li>API test mode：<code>chat-only</code></li><li>base URL：<code>https://api.modelarts-maas.com/v1</code></li><li>默认 model：例如 <code>DeepSeek-V3</code> 这样的稳定华为托管模型 ID</li></ul><h2 id="组件" tabindex="-1">组件 <a class="header-anchor" href="#组件" aria-label="Permalink to &quot;组件&quot;">​</a></h2><h3 id="_1-provider-registry" tabindex="-1">1. Provider Registry <a class="header-anchor" href="#_1-provider-registry" aria-label="Permalink to &quot;1. Provider Registry&quot;">​</a></h3><p>修改 <code>src/llmProviders.ts</code>：</p><ul><li>新增 <code>Qwen Code</code>、<code>Z AI</code> 与 <code>Huawei Cloud MaaS</code></li><li>将它们放在与相关 provider 相邻的合理顺序中</li><li>提供准确的描述与 setup hint</li><li>保留设置页依赖的现有 provider 排序语义</li></ul><h3 id="_2-runtime-与连接测试" tabindex="-1">2. Runtime 与连接测试 <a class="header-anchor" href="#_2-runtime-与连接测试" aria-label="Permalink to &quot;2. Runtime 与连接测试&quot;">​</a></h3><p>只要 provider 可以通过 <code>openai-compatible</code> 路由，就不应新增 runtime 分支。</p><p>实现应继续复用当前共享行为：</p><ul><li><code>callLLM()</code> 中针对 OpenAI-compatible 请求的 transport dispatch</li><li><code>testAPI()</code> 中基于 provider 元数据的 OpenAI-compatible probing</li><li>runtime 调用和连接测试共享的瞬时网络 fallback</li></ul><p>因此，新的 provider 需要的是元数据，而不是自定义 runtime 代码路径；除非实现评审证明存在无法通过当前元数据表达的 provider 兼容性问题。</p><h3 id="_3-文档" tabindex="-1">3. 文档 <a class="header-anchor" href="#_3-文档" aria-label="Permalink to &quot;3. 文档&quot;">​</a></h3><p>更新：</p><ul><li><code>README.md</code></li><li><code>README_zh.md</code></li><li><code>change.md</code></li></ul><p>文档应说明：</p><ul><li><code>Qwen Code</code> 是 coding-focused 预设</li><li><code>Z AI</code> 是对 <code>GLM</code> 的补充，而不是替代</li><li><code>Huawei Cloud MaaS</code> 作为托管式 OpenAI-compatible 选项可用</li></ul><p>provider 列表、配置说明与 preset 覆盖范围在两份 README 中必须保持同步。</p><h3 id="_4-发布" tabindex="-1">4. 发布 <a class="header-anchor" href="#_4-发布" aria-label="Permalink to &quot;4. 发布&quot;">​</a></h3><p>如果期间没有其他无关功能先落地，本工作应作为补丁版本 <code>1.7.6</code> 发布。</p><p>发布流程要求保持不变：</p><ul><li>GitHub release body 必须具备完整英文段与完整中文段</li><li>release 资产必须包含 <code>main.js</code>、<code>manifest.json</code>、<code>styles.css</code> 与 <code>README.md</code></li></ul><h2 id="错误处理" tabindex="-1">错误处理 <a class="header-anchor" href="#错误处理" aria-label="Permalink to &quot;错误处理&quot;">​</a></h2><p>新 provider 应继承现有共享的 retry 与 transient-failure fallback 行为。</p><p>本设计不新增 provider 级错误归一化。如果后续其中任何 provider 证明需要独立 response parser 或非标准 auth header，应单独拆出一份设计，因为那会把协议范围扩大到本轮之外。</p><p>当前规则继续保持：</p><ul><li>不要把 fatal client-status failure 当作瞬时网络错误重试</li><li>瞬时断连仍然通过现有稳定 fallback 路径重试</li></ul><h2 id="测试策略" tabindex="-1">测试策略 <a class="header-anchor" href="#测试策略" aria-label="Permalink to &quot;测试策略&quot;">​</a></h2><h3 id="provider-registry-测试" tabindex="-1">Provider Registry 测试 <a class="header-anchor" href="#provider-registry-测试" aria-label="Permalink to &quot;Provider Registry 测试&quot;">​</a></h3><p>扩展 <code>src/tests/llmProviders.test.ts</code>：</p><ul><li>断言 <code>Qwen Code</code>、<code>Z AI</code> 与 <code>Huawei Cloud MaaS</code> 存在</li><li>断言它们的 <code>transport</code> 与 <code>apiTestMode</code></li><li>确认它们被视为 OpenAI-compatible provider</li></ul><h3 id="runtime-routing-测试" tabindex="-1">Runtime Routing 测试 <a class="header-anchor" href="#runtime-routing-测试" aria-label="Permalink to &quot;Runtime Routing 测试&quot;">​</a></h3><p>扩展 <code>src/tests/llmUtilsProviderSupport.test.ts</code>：</p><ul><li>断言 <code>callLLM()</code> 会把每个新 provider 路由到 OpenAI-compatible runtime</li><li>断言实际使用的 endpoint、auth header 与 model 值符合预期</li></ul><h3 id="连接测试覆盖" tabindex="-1">连接测试覆盖 <a class="header-anchor" href="#连接测试覆盖" aria-label="Permalink to &quot;连接测试覆盖&quot;">​</a></h3><p>扩展 <code>src/tests/llmUtilsProviderSupport.test.ts</code>：</p><ul><li>断言 <code>testAPI()</code> 会对每个新 provider 探测预期的 <code>chat/completions</code> 路径</li><li>断言瞬时断连 fallback 也能在连接测试阶段覆盖这些新 preset</li></ul><h3 id="完整验证" tabindex="-1">完整验证 <a class="header-anchor" href="#完整验证" aria-label="Permalink to &quot;完整验证&quot;">​</a></h3><p>发布前：</p><ul><li>先跑定向 provider 测试，遵循 TDD</li><li>运行 <code>npm test -- --runInBand</code></li><li>运行 <code>npm run build</code></li><li>运行 <code>git diff --check</code></li><li>运行现有 Obsidian CLI 检查，并如实记录当前机器环境中的限制</li></ul><h2 id="评审说明" tabindex="-1">评审说明 <a class="header-anchor" href="#评审说明" aria-label="Permalink to &quot;评审说明&quot;">​</a></h2><p>本设计刻意只选择那些可以直接纳入现有 OpenAI-compatible transport 的 provider。任何需要专属 SDK、签名流程或新协议层的 provider，都继续延后处理。</p><p>当前会话没有用户明确授权进行子代理委派，因此未使用专门的 spec-review 子代理。本设计已经结合当前 provider registry、测试布局、发布规则，以及设计时参考的最新公开 Cline provider 目录和 provider 文档进行了自审。</p>',70)])])}const m=o(a,[["render",l]]);export{h as __pageData,m as default};
